import { Document, Packer, Paragraph, Table, TableCell, TableRow, TextRun, HeadingLevel } from 'docx';

export async function generateWordDocument(documentData, procedureData) {
  try {
    // Crear los párrafos para cada sección
    const sections = [
      createSection('OBJETIVO O PROPÓSITO', documentData.objetivo),
      createSection('ALCANCE', documentData.alcance),
      createSection('RESPONSABILIDADES', documentData.responsabilidades),
      createSection('NORMATIVA', documentData.normativa),
      createProcedureTable(procedureData),
      createSection('ANEXOS', documentData.anexos),
      createSection('TÉRMINOS Y REFERENCIAS', documentData.terminos)
    ].filter(section => section !== null);

    const doc = new Document({
      sections: [{
        properties: {},
        children: sections
      }]
    });

    // Generar el blob del documento
    const blob = await Packer.toBlob(doc);

    // Descargar el archivo
    saveAs(blob, 'Pago_Proveedores.docx');

  } catch (error) {
    console.error('Error generating Word document:', error);
    throw new Error('No se pudo generar el documento Word');
  }
}

function createSection(title, content) {
  if (!content || content.trim() === '') return null;

  return [
    new Paragraph({
      text: title,
      heading: HeadingLevel.HEADING_1,
      spacing: { after: 200 }
    }),
    new Paragraph({
      text: content,
      spacing: { after: 400 }
    })
  ];
}

function createProcedureTable(procedureData) {
  if (!procedureData || procedureData.length === 0) return null;

  const tableRows = [
    new TableRow({
      children: [
        new TableCell({ children: [new Paragraph('#')] }),
        new TableCell({ children: [new Paragraph('Quién')] }),
        new TableCell({ children: [new Paragraph('Actividad')] })
      ]
    })
  ];

  procedureData.forEach(row => {
    if (row.number || row.who || row.activity) {
      tableRows.push(
        new TableRow({
          children: [
            new TableCell({ children: [new Paragraph(row.number || '')] }),
            new TableCell({ children: [new Paragraph(row.who || '')] }),
            new TableCell({ children: [new Paragraph(row.activity || '')] })
          ]
        })
      );
    }
  });

  return new Table({
    width: { size: 100, type: 'pct' },
    rows: tableRows
  });
}

// Función para guardar el archivo (compatible con diferentes navegadores)
function saveAs(blob, filename) {
  const link = document.createElement('a');
  const url = URL.createObjectURL(blob);
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
}
